+        : TValue extends object
+          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
+          : TValue;
+
+/**
+ * Recursive schema interface.
+ */
+export interface RecursiveSchema<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> extends BaseSchema<
+    ReplaceRecur<InferInput<TWrapped>, InferRecursiveInput<TWrapped>>,
+    ReplaceRecur<InferOutput<TWrapped>, InferRecursiveOutput<TWrapped>>,
+    InferIssue<TWrapped>
+  > {
+  /** The schema type. */
+  readonly type: 'recursive';
+  /** The schema reference. */
+  readonly reference: typeof recursive;
+  /** The wrapped schema. */
+  readonly wrapped: TWrapped;
+}
+
+/**
+ * Infers the input type of a recursive schema.
+ */
+export type InferRecursiveInput<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> = ReplaceRecur<InferInput<TWrapped>, InferRecursiveInput<TWrapped>>;
+
+/**
+ * Infers the output type of a recursive schema.
+ */
+export type InferRecursiveOutput<
+  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
+> = ReplaceRecur<InferOutput<TWrapped>, InferRecursiveOutput<TWrapped>>;
+
+/**
+ * Placeholder for a self reference in a recursive schema.
+ */
+export const Recur: RecurSchema = {
+  kind: 'schema',
+  type: 'recur',
+  reference: recur,
+  expects: 'unknown',
+  async: false,
+  '~recur': true,
+  get '~standard'() {
+    return _getStandardProps(this);
+  },
+  '~run'(dataset, config) {
+    const schema = (config as typeof config & { '~recur'?: BaseSchema<unknown, unknown, BaseIssue<unknown>> })['~recur'];
+    if (!schema) {
+      throw new Error('Recursive placeholder must be wrapped with recursive() or recursiveAsync().');
+    }
+    return schema['~run'](dataset, config) as ReturnType<RecurSchema['~run']>;
+  },
+};
+
+function recur(): RecurSchema {
+  return Recur;
+}
+
+/**
+ * Creates a schema that resolves self references represented by `Recur`.
+ *
+ * @param wrapped The schema containing recursive placeholders.
+ *
+ * @returns A recursive schema.
+ */
+// @__NO_SIDE_EFFECTS__
+export function recursive<
+  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
