/**
 * Recursive placeholder schema interface.
 *
 * @internal
 */
interface RecurMarker {
  readonly '~recur': true;
}

export interface RecurSchema
  extends BaseSchema<RecurMarker, RecurMarker, never> {
  /** Whether this schema is a recursive placeholder. */
  readonly '~recur': true;
}

/**
 * Replaces recursive placeholders in a type.
 *
 * @internal
 */
export type ReplaceRecur<TValue, TRecur> = TValue extends RecurMarker
  ? TRecur
  : TValue extends Map<infer TKey, infer TValue>
    ? Map<ReplaceRecur<TKey, TRecur>, ReplaceRecur<TValue, TRecur>>
    : TValue extends Set<infer TValue>
      ? Set<ReplaceRecur<TValue, TRecur>>
      : TValue extends readonly (infer TValue)[]
        ? {
            -readonly [TKey in keyof TValue]: ReplaceRecur<
              TValue[TKey],
              TRecur
            >;
          }
        : TValue extends object
          ? { [TKey in keyof TValue]: ReplaceRecur<TValue[TKey], TRecur> }
          : TValue;

/**
 * Checks whether a type contains a recursive placeholder.
 *
 * @internal
 */
export type ContainsRecur<TValue> = TValue extends RecurMarker
  ? true
  : TValue extends Map<infer TKey, infer TValue>
    ? true extends ContainsRecur<TKey> | ContainsRecur<TValue>
      ? true
      : false
    : TValue extends Set<infer TValue>
      ? ContainsRecur<TValue>
      : TValue extends readonly unknown[]
        ? ContainsRecur<TValue[number]>
        : TValue extends object
          ? true extends {
              [TKey in keyof TValue]: ContainsRecur<TValue[TKey]>;
            }[keyof TValue]
            ? true
            : false
          : false;

/**
 * Recursive schema interface.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  TInput = InferInput<TWrapped>,
  TOutput = InferOutput<TWrapped>,
> extends BaseSchema<TInput, TOutput, InferIssue<TWrapped>> {
  /** The schema type. */
  readonly type: 'recursive';
  /** The schema reference. */
  readonly reference: typeof recur;
  /** The wrapped schema. */
  readonly wrapped: TWrapped;
  /** Whether this schema resolves recursive placeholders. */
  readonly '~recursive': true;
}

/**
 * Infers the input type of a recursive schema.
 *
 * @internal
 */
export type InferRecursiveInput<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = InferRecursiveValue<InferInput<TWrapped>, TWrapped, 'input'>;

/**
 * Infers the output type of a recursive schema.
 *
 * @internal
 */
export type InferRecursiveOutput<
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
> = InferRecursiveValue<InferOutput<TWrapped>, TWrapped, 'output'>;

/**
 * Infers a recursive value type.
 *
 * @internal
 */
type InferRecursiveValue<
  TValue,
  TWrapped extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
  TKind extends 'input' | 'output',
> = TValue extends RecurMarker
  ? TKind extends 'input'
